def _get_tpl(key): return _b64.b64decode(TEMPLATES_EXCEL[key])

# ══ MODULE UPLOAD UNIVERSEL ════════════════════════════════════════════════════
import io as _io_up

def _parse_xl(file_bytes):
    xl = pd.read_excel(_io_up.BytesIO(file_bytes), sheet_name=None, header=None)
    result = {}
    for sn, df_raw in xl.items():
        if len(df_raw) < 2: continue
        r0 = df_raw.iloc[0].tolist()
        r1 = df_raw.iloc[1].tolist() if len(df_raw)>1 else []
        if any(str(v) not in ['nan','None',''] for v in r1):
            hdrs=[str(r1[i]) if str(r1[i]) not in ['nan','None',''] else (str(r0[i]) if str(r0[i]) not in ['nan','None',''] else f'Col{i}') for i in range(max(len(r0),len(r1)))]
            data=df_raw.iloc[2:].copy()
        else:
            hdrs=[str(h) if str(h) not in ['nan','None',''] else f'Col{i}' for i,h in enumerate(r0)]
            data=df_raw.iloc[1:].copy()
        seen={}; ch=[]
        for h in hdrs:
            if h in seen: seen[h]+=1; ch.append(f"{h}_{seen[h]}")
            else: seen[h]=0; ch.append(h)
        data.columns=ch[:len(data.columns)]
        result[sn]=data.dropna(how='all').reset_index(drop=True)
    return result

def _detect(df):
    d={}
    for c in df.columns:
        cl=c.lower()
        if any(x in cl for x in ['sondage','hole','bhid']) and 'id' not in d: d['id']=c
        elif cl in ['from','de','from_m','depth_from'] and 'frm' not in d: d['frm']=c
        elif cl in ['to','a','to_m','depth_to'] and 'to' not in d: d['to']=c
        elif 'litho' in cl and 'litho' not in d: d['litho']=c
        elif ('easting' in cl or cl=='x') and 'x' not in d: d['x']=c
        elif ('northing' in cl or cl=='y') and 'y' not in d: d['y']=c
        elif 'au' in cl and any(x in cl for x in ['ppb','ppm','labo']) and 'au' not in d: d['au']=c
        elif 'alter' in cl and 'alt' not in d: d['alt']=c
        elif ('coul' in cl or 'color' in cl) and 'coul' not in d: d['coul']=c
        elif ('dur' in cl or 'hard' in cl) and 'dur' not in d: d['dur']=c
        elif 'ip' in cl and 'charge' in cl and 'ip' not in d: d['ip']=c
    return d

def _show_upload(ukey, label, tpl_key, color="#1A237E"):
    """Widget upload universel — visible en haut de chaque onglet"""
    # Bannière upload
    st.markdown(f"""
    <div style='background:{color}18;border:2.5px solid {color};border-radius:12px;
    padding:14px 18px;margin:6px 0 10px;'>
    <h4 style='color:{color};margin:0 0 6px;font-size:15px;'>
    📂 Charger vos données terrain — {label}</h4>
    <p style='color:#555;font-size:11px;margin:0;'>
    Importez votre fichier Excel pour analyser automatiquement vos données
    (logue visuel, carte spatiale, analyse Au, export CSV)</p>
    </div>""", unsafe_allow_html=True)

    col_u1, col_u2 = st.columns([3, 1])
    with col_u1:
        up_file = st.file_uploader(
            f"📁 Sélectionner un fichier Excel (.xlsx ou .xls)",
            type=['xlsx', 'xls'],
            key=f'up_{ukey}',
            help="Chargez le template fourni rempli avec vos données terrain, ou tout fichier Excel standard"
        )
    with col_u2:
        if tpl_key in TEMPLATES_INFO:
            ti = TEMPLATES_INFO[tpl_key]
            st.markdown(f"<small style='color:{color};font-weight:bold;'>📥 Template à remplir :</small>", unsafe_allow_html=True)
            st.download_button(
                label=f"{ti['icone']} {ti['nom'][:22]}",
                data=_get_tpl(tpl_key),
                file_name=ti['nom'],
                mime='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                key=f'dl_up_{ukey}',
                use_container_width=True,
                type="primary"
            )

    if up_file is not None:
        fb = up_file.read()
        data_dict = _parse_xl(fb)
        sheets = list(data_dict.keys())
        st.success(f"✅ **{up_file.name}** chargé — {len(sheets)} feuille(s) : {', '.join(sheets)}")

        col_sh1, col_sh2 = st.columns([2, 1])
        with col_sh1:
            sn_sel = st.selectbox("📄 Feuille", sheets, key=f'sn_{ukey}')
        df = data_dict[sn_sel].copy()
        det = _detect(df)

        with col_sh2:
            if det.get('id') and det['id'] in df.columns:
                ids = ['Tous'] + df[det['id']].dropna().unique().tolist()
                id_s = st.selectbox("🔩 Sondage/ID", ids, key=f'ids_{ukey}')
                if id_s != 'Tous':
                    df = df[df[det['id']] == id_s].copy()

        # KPIs automatiques
        kpi_items = [("📊 Lignes", len(df), ""), ("📋 Colonnes", len(df.columns), "")]
        if det.get('au') and det['au'] in df.columns:
            try:
                au_n = pd.to_numeric(df[det['au']], errors='coerce').dropna()
                if len(au_n) > 0:
                    kpi_items.append(("🥇 Au max", f"{au_n.max():.1f} ppb",
                                     "🔴" if au_n.max()>=2000 else "🟠" if au_n.max()>=500 else "🟡" if au_n.max()>=100 else "⚪"))
                    kpi_items.append(("Au ≥ 100ppb", int((au_n>=100).sum()), ""))
            except: pass
        if det.get('frm') and det.get('to') and det['frm'] in df.columns:
            try:
                p = pd.to_numeric(df[det['to']], errors='coerce').max()
                kpi_items.append(("📏 Prof. max", f"{p:.0f}m", ""))
            except: pass
        if det.get('ip') and det['ip'] in df.columns:
            try:
                ip_n = pd.to_numeric(df[det['ip']], errors='coerce').dropna()
                if len(ip_n) > 0:
                    kpi_items.append(("📡 IP max", f"{ip_n.max():.1f}", "🔴" if ip_n.max()>20 else ""))
            except: pass

        k_cols = st.columns(min(5, len(kpi_items)))
        for i, (lbl, val, bdg) in enumerate(kpi_items[:5]):
            k_cols[i].metric(lbl, val)

        # Sous-onglets analyse
        stabs = st.tabs(["📋 Données", "📊 Logue visuel", "🗺️ Carte spatiale", "🔍 Analyse", "📤 Export"])

        with stabs[0]:
            st.dataframe(df, use_container_width=True, height=320)
            for sn2 in sheets:
                if sn2 != sn_sel:
                    with st.expander(f"📄 Feuille : {sn2}"):
                        st.dataframe(data_dict[sn2], use_container_width=True, height=200)

        with stabs[1]:
            col_f = det.get('frm'); col_t = det.get('to')
            if col_f and col_t and col_f in df.columns and col_t in df.columns:
                _lc = {'latérite':'#8B4513','laterite':'#8B4513','lat':'#8B4513',
                       'saprolite':'#DAA520','sap':'#DAA520','saprock':'#CD853F',
                       'schiste':'#696969','sch':'#696969','quartzite':'#FFD700',
                       'qtz':'#FFD700','granite':'#708090','sol':'#2D5016'}
                vis = [(det.get('litho'),'Lithologie'),(det.get('coul'),'Couleur'),(det.get('alt'),'Altération')]
                vis = [(c,l) for c,l in vis if c and c in df.columns]
                has_au = det.get('au') and det['au'] in df.columns
                ncv = max(1, len(vis)) + (1 if has_au else 0)
                fig_lg, axes_lg = plt.subplots(1, ncv, figsize=(3.2*ncv, 12), sharey=True)
                if ncv == 1: axes_lg = [axes_lg]
                ci = 0
                for col_v, lbl_v in vis:
                    for _, row in df.iterrows():
                        try:
                            de=float(str(row[col_f]).replace(',','.') or 0)
                            a=float(str(row[col_t]).replace(',','.') or de+1)
                            val=str(row.get(col_v,''))
                            cl='#CCCCCC'
                            for k,v in _lc.items():
                                if k in val.lower(): cl=v; break
                            axes_lg[ci].fill_betweenx([de,a],0,1,color=cl,alpha=0.85)
                            axes_lg[ci].plot([0,1],[de,de],'k-',linewidth=0.3)
                            if (a-de)>=1.5: axes_lg[ci].text(0.5,(de+a)/2,val[:10],ha='center',va='center',fontsize=5,fontweight='bold')
                            if ci==0: axes_lg[ci].text(-0.08,de,f"{de:.0f}m",ha='right',fontsize=5)
                        except: pass
                    axes_lg[ci].set_title(lbl_v,fontsize=8,fontweight='bold'); axes_lg[ci].set_xticks([])
                    if ci==0: axes_lg[ci].set_ylabel("Profondeur (m)",fontsize=8)
                    ci+=1
                if has_au:
                    fv,tv,auv=[],[],[]
                    for _,row in df.iterrows():
                        try:
                            fv.append(float(str(row[col_f]).replace(',','.') or 0))
                            tv.append(float(str(row[col_t]).replace(',','.') or 0))
                            auv.append(float(str(row[det['au']]).replace(',','.') or 0))
                        except: pass
                    if auv:
                        miv=[(f+t)/2 for f,t in zip(fv,tv)]; htv=[(t-f)*0.8 for f,t in zip(fv,tv)]
                        cav=['#FF0000' if v>=2000 else '#FF6600' if v>=500 else '#FFD700' if v>=100 else '#EEE' for v in auv]
                        axes_lg[ci].barh(miv,auv,height=htv,color=cav,edgecolor='orange',linewidth=0.3)
                        axes_lg[ci].axvline(x=100,color='red',linestyle='--',linewidth=1.5,label='100ppb')
                        axes_lg[ci].set_title("Au (ppb)",fontsize=8,fontweight='bold'); axes_lg[ci].legend(fontsize=6)
                for ax in axes_lg:
                    if ax.get_ylim()[0] < ax.get_ylim()[1]: ax.invert_yaxis()
                lp_l=[mpatches.Patch(color=v,label=k.capitalize()) for k,v in list(_lc.items())[:6]]
                axes_lg[0].legend(handles=lp_l,loc='lower right',fontsize=5,title='Litho',framealpha=0.9)
                plt.suptitle(f"Logue — {up_file.name}",fontsize=10,fontweight='bold')
                plt.tight_layout(); st.pyplot(fig_lg); plt.close()
            else:
                st.info("💡 Logue visuel : colonnes From/To requises dans votre fichier Excel.")
                st.info(f"Colonnes détectées : {list(det.keys())}")

        with stabs[2]:
            cx=det.get('x'); cy=det.get('y'); cau=det.get('au')
            if cx and cy and cx in df.columns and cy in df.columns:
                fig_mp,ax_mp=plt.subplots(figsize=(10,8))
                fig_mp.patch.set_facecolor('#F5F5F0'); ax_mp.set_facecolor('#E8F4F8')
                if cau and cau in df.columns:
                    try:
                        av=pd.to_numeric(df[cau],errors='coerce').fillna(0)
                        sc=ax_mp.scatter(df[cx].astype(float),df[cy].astype(float),
                                        c=av,cmap='YlOrRd',s=100,edgecolors='black',linewidths=0.5,zorder=3,alpha=0.85)
                        plt.colorbar(sc,ax=ax_mp,label=f'{cau}')
                    except:
                        ax_mp.scatter(df[cx].astype(float),df[cy].astype(float),c='#2196F3',s=100,edgecolors='black',zorder=3)
                else:
                    ax_mp.scatter(df[cx].astype(float),df[cy].astype(float),c='#2196F3',s=100,edgecolors='black',zorder=3)
                if det.get('id') and det['id'] in df.columns:
                    for _,row in df.head(20).iterrows():
                        try: ax_mp.text(float(row[cx]),float(row[cy])+5,str(row[det['id']])[:8],fontsize=6,ha='center',color='#1A237E',fontweight='bold')
                        except: pass
                ax_mp.set_xlabel("Easting (m)"); ax_mp.set_ylabel("Northing (m)")
                ax_mp.set_title(f"Carte — {up_file.name}",fontsize=11,fontweight='bold')
                ax_mp.grid(True,linestyle=':',alpha=0.4)
                plt.tight_layout(); st.pyplot(fig_mp); plt.close()
            else:
                st.info("💡 Carte spatiale : colonnes Easting et Northing requises.")
                st.info(f"Colonnes détectées : {list(det.keys())}")

        with stabs[3]:
            auc=det.get('au')
            if auc and auc in df.columns:
                try:
                    an=pd.to_numeric(df[auc],errors='coerce').dropna()
                    if len(an)>0:
                        mx=an.max()
                        if mx>=2000: st.error(f"🔴 HAUTE TENEUR — Au={mx:.1f}ppb → Cible économique !")
                        elif mx>=500: st.warning(f"🟠 SIGNIFICATIF — Au={mx:.1f}ppb → Confirmer par forage")
                        elif mx>=100: st.info(f"🟡 ANOMALIQUE — Au={mx:.1f}ppb → À investiguer")
                        else: st.success(f"⚪ FOND — Au={mx:.1f}ppb")
                        anom=df[pd.to_numeric(df[auc],errors='coerce')>=100]
                        if len(anom)>0:
                            sc=[c for c in [det.get('id'),det.get('frm'),det.get('to'),det.get('litho'),auc] if c and c in df.columns]
                            st.markdown(f"**{len(anom)} intervalles ≥ 100ppb :**")
                            st.dataframe(anom[sc] if sc else anom,use_container_width=True)
                except: pass
            nc=df.select_dtypes(include='number').columns.tolist()
            if nc:
                st.markdown("**Statistiques descriptives :**")
                st.dataframe(df[nc].describe().round(2),use_container_width=True)

        with stabs[4]:
            ec1,ec2=st.columns(2)
            with ec1:
                st.download_button("📥 CSV feuille active",data=df.to_csv(index=False),
                    file_name=f"{sn_sel}_{ukey}.csv",mime='text/csv',key=f'exp1_{ukey}')
            with ec2:
                ac=chr(10).join(["=== "+str(sn)+" ==="+chr(10)+data_dict[sn].to_csv(index=False) for sn in sheets])
                st.download_button("📥 Toutes feuilles",data=ac,
                    file_name=f"all_{ukey}.txt",mime='text/plain',key=f'exp2_{ukey}')
    else:
        st.markdown(f"""
        <div style='background:#F9F9F9;border:2px dashed {color};border-radius:12px;
        padding:20px;text-align:center;'>
        <div style='font-size:36px;'>📂</div>
        <h4 style='color:{color};margin:6px 0;'>Aucun fichier chargé</h4>
        <p style='color:#777;font-size:11px;margin:0;'>
        1️⃣ Téléchargez le template Excel<br>
        2️⃣ Remplissez vos données terrain (champs 🟡 jaunes obligatoires)<br>
        3️⃣ Rechargez le fichier ici → analyse automatique
        </p></div>""", unsafe_allow_html=True)


