    with col2_sl:

        # ── MODE 1 & 2 : FAIBLE INCLINAISON / SUBHORIZONTAL ────────────────
        if "faible inclinaison" in slow_mode or "subhorizontal" in slow_mode:

            # Générer des forages synthétiques avec les bonnes inclinaisons
            np.random.seed(p_actif['seed'] + 200)
