            df_slow = pd.DataFrame(forages_slow)

            # Figure
            fig_sl, ax_sl = plt.subplots(figsize=(16, 9))
            fig_sl.patch.set_facecolor('#F0EDE5')
            ax_sl.set_facecolor('#E8F4F8')

            # Topographie
            x_topo_sl = np.linspace(0, 900, 400)
