                ax_c.set_xlim(-0.15,1.25)
                ax_c.set_xticks([])
                if ci==0: ax_c.set_ylabel("Profondeur (m)",fontsize=9)

                # Espacement entre trous
                if ci>0:
                    esp_m = x_corr[ci]-x_corr[ci-1]
