        col2.metric("🔴 Erreurs critiques",len([e for e in erreurs if 'CRITIQUE' in e['sévérité']]))
        col3.metric("🟠 Erreurs",len([e for e in erreurs if 'ERREUR' in e['sévérité']]))
        col4.metric("🟡 Avertissements",len(avertissements))

        # Barre de score
