            if couleur_ia in ['Brun/Ocre','Jaune/Doré'] and profondeur_ia < 15:
                scores['Latérite'] += 40
                scores['Saprolite'] += 20
            if couleur_ia == 'Brun/Ocre' and profondeur_ia >= 15 and profondeur_ia < 30:
                scores['Saprolite'] += 40
            if profondeur_ia >= 25 and profondeur_ia < 50:
                scores['Saprock'] += 25
