            # Dureté
            if durete_ia >= 7: scores['Quartzite aurifère'] += 20; scores['Granite frais'] += 15
            elif durete_ia <= 3: scores['Latérite'] += 20; scores['Saprolite'] += 20
            elif durete_ia <= 5: scores['Saprock'] += 15; scores['Bédrock/Schiste'] += 10

            litho_result = max(scores, key=scores.get)
